+    #[test]
+    fn walk_empty_tree_visits_nothing() {
+        let cx = test_cx();
+        let dev = MemBlockDevice::new(4096);
+        let root = make_root();
+
+        let mut visited = Vec::new();
+        let count = walk(&cx, &dev, &root, &mut |ext| {
+            visited.push(*ext);
+            Ok(())
+        })
+        .unwrap();
+
+        assert_eq!(count, 0);
+        assert!(visited.is_empty());
+    }
